"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";
import { createBoard } from "@/util/boardApi";
import Editor from "@/components/Editor";
import "../board.css"; // CSS 경로 확인

export default function BoardWritePage() {
  const router = useRouter();
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");

  const handleSubmit = async () => {
    const token = localStorage.getItem("token");
    if (!token) return alert("로그인이 필요합니다.");
    try {
      await createBoard(token, { title, content });
      router.push("/board");
    } catch { alert("작성 실패"); }
  };

  return (
    <div className="board-container">
      <div className="board-header">
        <h1 className="board-title">글쓰기</h1>
      </div>
      
      <input 
        type="text" 
        className="input-field" 
        placeholder="제목을 입력하세요" 
        value={title} 
        onChange={e => setTitle(e.target.value)} 
      />
      
      {/* 에디터 컴포넌트 */}
      <Editor value={content} onChange={setContent} />

      <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '10px', marginTop: '20px' }}>
        <button onClick={() => router.back()} className="btn btn-secondary">취소</button>
        <button onClick={handleSubmit} className="btn btn-primary">등록</button>
      </div>
    </div>
  );
}